import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './ERPChatBot.css';
import { 
  Send, 
  User, 
  Bot, 
  Trash2, 
  Calendar, 
  BookOpen, 
  DollarSign, 
  FileText,
  Clock,
  Loader2
} from 'lucide-react';

const ChatbotInterface = ({ studentData }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [quickActions, setQuickActions] = useState([]);
  const messagesEndRef = useRef(null);

  // Initialize with welcome message
  useEffect(() => {
    const welcomeMessage = {
      id: 'welcome',
      type: 'bot',
      content: `Hello ${studentData?.firstName || 'Student'}! I'm your AI assistant. I can help you with fees, grades, attendance, schedule, and all academic information.`,
      timestamp: new Date()
    };
    
    setMessages([welcomeMessage]);
    generateQuickActions();
  }, [studentData]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  // Generate quick actions based on student data
  const generateQuickActions = () => {
    const actions = [
      {
        icon: <DollarSign size={18} />,
        text: 'My Fees',
        query: 'What are my current semester fees and payment status?'
      },
      {
        icon: <BookOpen size={18} />,
        text: 'My Grades',
        query: 'Show my grades and GPA for this semester'
      },
      {
        icon: <Calendar size={18} />,
        text: 'Today\'s Schedule',
        query: 'What classes do I have today?'
      },
      {
        icon: <FileText size={18} />,
        text: 'Attendance',
        query: 'What is my attendance percentage in current courses?'
      },
      {
        icon: <Clock size={18} />,
        text: 'Assignments',
        query: 'Do I have any pending assignments or tasks?'
      }
    ];
    
    setQuickActions(actions);
  };

  const sendMessage = async (customQuery = null) => {
    const query = customQuery || input.trim();
    if (!query) return;

    const userMessage = {
        id: Date.now(),
        type: 'user',
        content: query,
        timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setLoading(true);
    setIsTyping(true);

    try {
        const response = await axios.post('/api/chatbot/ask', {
            question: query
        }, {
            headers: {
                'Authorization': `Bearer ${localStorage.getItem('token')}`
            },
            withCredentials: true // Important for session cookies
        });

        const botMessage = {
            id: Date.now() + 1,
            type: 'bot',
            content: response.data.answer,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, botMessage]);
    } catch (error) {
        console.error('Error:', error);
        
        // More detailed error message
        let errorMessage = 'I encountered an error. Please try again or contact support.';
        
        if (error.response) {
            if (error.response.status === 401) {
                errorMessage = 'Please log in to use the chatbot.';
            } else if (error.response.status === 404) {
                errorMessage = 'Student record not found. Please contact administration.';
            } else if (error.response.data?.message) {
                errorMessage = error.response.data.message;
            }
        }
        
        const errorMessageObj = {
            id: Date.now() + 1,
            type: 'bot',
            content: errorMessage,
            timestamp: new Date()
        };
        setMessages(prev => [...prev, errorMessageObj]);
    } finally {
        setLoading(false);
        setIsTyping(false);
    }
};

  const handleQuickAction = (query) => {
    sendMessage(query);
  };

  const clearChat = () => {
    setMessages([]);
    const welcomeMessage = {
      id: 'welcome',
      type: 'bot',
      content: `Hello ${studentData?.firstName || 'Student'}! How can I help you today?`,
      timestamp: new Date()
    };
    setMessages([welcomeMessage]);
    
    // Call API to clear backend history
    axios.post('/api/chatbot/clear-history', {}, {
      headers: {
        'Authorization': `Bearer ${localStorage.getItem('token')}`
      }
    });
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const formatTime = (date) => {
    return new Date(date).toLocaleTimeString([], { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
  };

  // Example questions for new users
  const exampleQuestions = [
    "What's my total fee for this semester?",
    "Show my attendance in current courses",
    "What are my grades this semester?",
    "What's my class schedule for today?",
    "Do I have any pending assignments?",
    "What's my GPA and academic progress?",
    "When does the next semester start?",
    "How much do I owe in total fees?"
  ];

  return (
    <div className="chatbot-container">
      {/* Header */}
      <div className="chatbot-header">
        <div className="header-left">
          <div className="bot-avatar">
            <Bot size={24} />
          </div>
          <div className="header-info">
            <h3>University AI Assistant</h3>
            <p className="student-info">
              {studentData?.firstName} {studentData?.lastName} • Semester {studentData?.currentSemester}
            </p>
          </div>
        </div>
        <button 
          onClick={clearChat}
          className="clear-btn"
          title="Clear chat history"
        >
          <Trash2 size={18} />
          Clear Chat
        </button>
      </div>

      {/* Chat Messages Area */}
      <div className="chat-messages">
        {messages.map((message) => (
          <div 
            key={message.id} 
            className={`message ${message.type}`}
          >
            <div className="message-avatar">
              {message.type === 'user' ? (
                <div className="user-avatar">
                  <User size={16} />
                </div>
              ) : (
                <div className="bot-avatar-small">
                  <Bot size={16} />
                </div>
              )}
            </div>
            <div className="message-content-wrapper">
              <div className="message-content">
                {message.content.split('\n').map((line, i) => (
                  <p key={i}>{line}</p>
                ))}
              </div>
              <div className="message-time">
                {formatTime(message.timestamp)}
              </div>
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="message bot typing">
            <div className="message-avatar">
              <div className="bot-avatar-small">
                <Bot size={16} />
              </div>
            </div>
            <div className="message-content-wrapper">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          </div>
        )}

        {messages.length === 1 && (
          <div className="welcome-section">
            <div className="quick-actions">
              <h4>Quick Actions</h4>
              <div className="actions-grid">
                {quickActions.map((action, index) => (
                  <button
                    key={index}
                    className="action-btn"
                    onClick={() => handleQuickAction(action.query)}
                    disabled={loading}
                  >
                    <span className="action-icon">{action.icon}</span>
                    <span className="action-text">{action.text}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="example-questions">
              <h4>Try asking me:</h4>
              <div className="questions-grid">
                {exampleQuestions.map((question, index) => (
                  <button
                    key={index}
                    className="question-btn"
                    onClick={() => setInput(question)}
                    disabled={loading}
                  >
                    {question}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="chat-input-container">
        <div className="input-wrapper">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask me anything about your academic information..."
            rows="1"
            disabled={loading}
          />
          <button
            onClick={() => sendMessage()}
            disabled={loading || !input.trim()}
            className="send-btn"
          >
            {loading ? (
              <Loader2 size={20} className="spin" />
            ) : (
              <Send size={20} />
            )}
          </button>
        </div>
        <div className="input-hint">
          Press Enter to send • Shift+Enter for new line
        </div>
      </div>
    </div>
  );
};

export default ChatbotInterface;
